precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
uniform vec2 u_resolution;
varying vec2 v_uv;

void main()
{
    vec2 uv = v_uv;
    float offset = 0.01;
    float glitch_strength = 0.05;

    vec3 redChannel = texture2D(u_texture, uv + vec2(gl_FragCoord.x * offset, 0.0)).rgb;
    vec3 blueChannel = texture2D(u_texture, uv - vec2(gl_FragCoord.x * offset, 0.0)).rgb;

    vec3 color = vec3(redChannel.r, 0.0, blueChannel.b);

    gl_FragColor = vec4(clamp(color, 0.0, 1.0), 1.0);
}
